class Inventory:
    def __init__(self):
        self.products = {}

    def add_product(self, product_name, price):
        self.products[product_name] = price

    @staticmethod
    def get_total_inventory_value(products):
        return sum(products.values())

# Do not modify the code below. This function will be called during testing.
def default_test():
    inventory = Inventory()
    inventory.add_product("Laptop", 50000)
    inventory.add_product("Phone", 15000)
    print(inventory.products)
    print(Inventory.get_total_inventory_value(inventory.products))
